import sqlite3
from pathlib import Path


ROOT = Path(__file__).resolve().parents[1]


def test_correction_handoff_and_void_leave_a_complete_consistent_report():
    db = sqlite3.connect(":memory:")
    db.row_factory = sqlite3.Row
    for path in (
        "sql/001_schema.sql",
        "sql/010_batch_state.sql",
        "sql/020_posted_lines.sql",
    ):
        db.executescript((ROOT / path).read_text())

    db.executemany(
        "INSERT INTO wallets VALUES (?, ?)",
        [("north", "North"), ("south", "South"), ("archive", "Archive")],
    )
    db.execute("INSERT INTO settlement_batches VALUES ('cycle-9', 'draft', 'Cycle nine')")
    db.executemany(
        "INSERT INTO settlement_lines VALUES (?, 'cycle-9', ?, ?)",
        [("north-leg", "north", 90), ("south-leg", "south", -90)],
    )
    db.execute("UPDATE settlement_batches SET status = 'posted' WHERE batch_id = 'cycle-9'")
    db.execute("UPDATE settlement_batches SET label = 'Cycle 09' WHERE batch_id = 'cycle-9'")
    db.execute(
        "UPDATE settlement_lines SET wallet_id = 'archive', cents = 110 "
        "WHERE line_id = 'north-leg'"
    )

    materialized_before_void = dict(
        db.execute("SELECT wallet_id, settled_cents FROM wallet_totals")
    )
    assert materialized_before_void == {"archive": 110, "north": 0, "south": -90}

    before_void = {
        row["wallet_id"]: (row["settled_cents"], row["draft_cents"])
        for row in db.execute((ROOT / "sql/wallet_report.sql").read_text())
    }
    assert before_void == {
        "archive": (110, 0),
        "north": (0, 0),
        "south": (-90, 0),
    }

    db.execute("UPDATE settlement_batches SET status = 'void' WHERE batch_id = 'cycle-9'")
    assert dict(db.execute("SELECT wallet_id, settled_cents FROM wallet_totals")) == {
        "archive": 0,
        "north": 0,
        "south": 0,
    }
    after_void = {
        row["wallet_id"]: (row["settled_cents"], row["draft_cents"])
        for row in db.execute((ROOT / "sql/wallet_report.sql").read_text())
    }
    assert after_void == {
        "archive": (0, 0),
        "north": (0, 0),
        "south": (0, 0),
    }
